// 实现TWAP预言机 contract TWAPOracle { struct Observation { uint32 timestamp; uint256 price; } mapping(address =&gt; Observation[]) public observations; uint256 public constant WINDOW = 30 minutes; // 时间窗口 function getTWAP(address token) external view returns (uint256) { Observation[] storage tokenObservations = observations[token]; uint256 length = tokenObservations.length; require(length &gt; 0, &#34;No observations&#34;); uint256 totalWeightedPrice = 0; uint256 totalTime = 0; for (uint i = 1; i &lt; length; i++) { uint256 timeDelta = tokenObservations[i].timestamp - tokenObservations[i-1].timestamp; if (timeDelta &gt; 0) { uint256 avgPrice = (tokenObservations[i-1].price + tokenObservations[i].price) / 2; totalWeightedPrice += avgPrice * timeDelta; totalTime += timeDelta; } } require(totalTime &gt; 0 &amp;&amp; totalTime &gt;= WINDOW, &#34;Insufficient data&#34;); return totalWeightedPrice / totalTime; } } 价格边界检查
// 添加价格合理性检查 contract ThunderLoan { // 价格波动限制（例如：±10%） uint256 public constant MAX_PRICE_DEVIATION = 10; // 10% mapping(address =&gt; uint256) public lastPrices; function getPriceInWethWithCheck(address token) internal returns (uint256) { uint256 currentPrice = getPriceInWeth(token); uint256 lastPrice = lastPrices[token]; if (lastPrice &gt; 0) { uint256 deviation = (currentPrice &gt; lastPrice) ? ((currentPrice - lastPrice) * 100) / lastPrice : ((lastPrice - currentPrice) * 100) / lastPrice; require(deviation &lt;= MAX_PRICE_DEVIATION, &#34;Price deviation too high&#34;); } lastPrices[token] = currentPrice; return currentPrice; } } 延迟价格更新
// 使用延迟的价格更新 contract DelayedOracle { struct PriceData { uint256 price; uint256 timestamp; bool isValid; } mapping(address =&gt; PriceData) public pendingPrices; uint256 public constant DELAY = 5 minutes; // 5分钟延迟 function requestPriceUpdate(address token) external { uint256 currentPrice = getRealTimePrice(token); pendingPrices[token] = PriceData({ price: currentPrice, timestamp: block.timestamp, isValid: true }); } function getPrice(address token) external view returns (uint256) { PriceData memory data = pendingPrices[token]; require(data.isValid, &#34;No valid price&#34;); require(block.timestamp &gt;= data.timestamp + DELAY, &#34;Price not ready&#34;); return data.price; } } 集成Chainlink等去中心化预言机
// 使用Chainlink import &#34;@chainlink/contracts/src/v0.8/interfaces/AggregatorV3Interface.sol&#34;; contract ChainlinkOracle { AggregatorV3Interface internal priceFeed; constructor(address _aggregator) { priceFeed = AggregatorV3Interface(_aggregator); } function getPrice() public view returns (uint256) { ( uint80 roundId, int256 price, uint256 startedAt, uint256 updatedAt, uint80 answeredInRound ) = priceFeed.latestRoundData(); // 数据质量检查 require(price &gt; 0, &#34;Invalid price&#34;); require(updatedAt &gt;= block.timestamp - 1 hours, &#34;Stale price&#34;); require(answeredInRound &gt;= roundId, &#34;Stale round&#34;); return uint256(price); } }
